sqlMap.select:
/* CapitalDAO.selectERPINSetList */

	select * from (
	select 
		AccSeq, 
		AccNo, 
		AccName,  
		CASE WHEN ISNULL(B.sType,0) = 0 THEN 'N' ELSE 'Y' END as sType 
	from SGERP.dbo._TDAAccount A WITH(NOLOCK)
	left join SGERP.dbo.IFRS_CAPITALSTD B WITH(NOLOCK) on A.CompanySeq = B.CompanySeq AND A.AccNo = B.sData AND B.sType = 1
	where A.CompanySeq = #comNo#) T1 where T1.sType = #sType# order by T1.sType desc, T1.AccNo;

/* CapitalDAO.selectCMSINSetList */

select * from (
select B.BankName, A.BankAccNo, A.BankAccName, CASE WHEN ISNULL(C.sType,0) = 0 THEN 'N' ELSE 'Y' END as sType from SGERP.dbo._TDABankAcc A WITH(NOLOCK)
left join SGERP.dbo._TDABank B WITH(NOLOCK) on B.CompanySeq = #comNo# AND A.BankSeq = B.BankSeq
left join SGERP.dbo.IFRS_CAPITALSTD C WITH(NOLOCK) on C.CompanySeq = #comNo# AND A.BankAccNo = C.sData AND C.sType = #sType1#
where A.CompanySeq = #comNo#) T1 where T1.sType = #sType# order by T1.sType desc, T1.BankName, T1.BankAccNo;

/* CapitalDAO.selectLoadSaveData */

		
select * from TB_CAPITAL_ASSET WITH(NOLOCK) where companyseq = #comNo# and sdate = #sdate2#;




		
select * from TB_CAPITAL_ASSET_BAK WITH(NOLOCK) where companyseq = #comNo# and sdate = #sdate2#;

sqlMap.delete:
/* CapitalDAO.IfrsCapitalDeleteAjax */

	DELETE FROM TB_CAPITAL_LIST	
	WHERE companyseq = #CompanySeq#	
	AND sDate >= #sdate# AND sDate <= #edate#;
	
	DELETE FROM TB_CAPITAL_ASSET	
	WHERE companyseq = #CompanySeq#	
	AND sdate >= #sdate# AND sdate <= #edate#;

sqlMap.select:
/* CapitalDAO.selectDeptCd */
		
	select * from FIM.dbo.TB_DEPARTMENT WITH(NOLOCK) where DEPT_MAIL_ID like #deptmail# 			
	AND DEPT_STATUS = 'Y';

/* CapitalDAO.selectDeptMail */
		
	SELECT A.LOGON_ID from FIM.dbo.TB_USER A WITH(NOLOCK)
	INNER JOIN FIM.dbo.TB_DEPARTMENT B WITH(NOLOCK) on A.DEPT_CD = B.DEPT_CD
	WHERE B.DEPT_CD_PATH like '%'+#deptmail#+'%' AND A.USE_FG = '1';

sqlMap.insert:
/* CapitalDAO.insertCompanyGraphSetting */ INSERT INTO TB_COMPANY_GRAPH_SETTING ( COM_NO ,MAX_AMT
,SPLIT_INTERVAL ,INS_ID ,INS_DT ) VALUES ( #comNo# ,#maxAmt#
,#splitInterval# ,#userId# ,GETDATE() )

sqlMap.update:
/* CapitalDAO.updateCompanyGraphSetting */ UPDATE TB_COMPANY_GRAPH_SETTING SET MAX_AMT = #maxAmt#
,SPLIT_INTERVAL = #splitInterval# ,UPD_ID = #userId# ,UPD_DT = GETDATE()
WHERE COM_NO = #comNo#

sqlMap.select:
/* CapitalDAO.selectLoadNonErpSaveData */
SELECT DocNo, stype, companyseq, sdate, sdata1, sdata2, sdata3, sdata4, sdata5, sum4 as sum1, 0 as sum2, 0as sum3, sum4, sum5, sum6, sum7, sum8, sum9, INS_ID, INS_DT FROM TB_CAPITAL_ASSET WITH(NOLOCK) WHERE companyseq = #comNo# and sdate = #sdate2#
SELECT DocNo, stype, companyseq, sdate, sdata1, sdata2, sdata3, sdata4, sdata5, sum4 as sum1, 0 as sum2, 0as sum3, sum4, sum5, sum6, sum7, sum8, sum9 FROM TB_CAPITAL_ASSET_BAK WITH(NOLOCK) WHERE companyseq = #comNo# and sdate = #sdate2#

sqlMap.insert:
/* CapitalDAO.setFcmmnLog */
INSERT INTO FIM.dbo.TB_FCMMN_LOG ( SYSTEM_CD,	LEVEL,	REG_DATE,	LOG_JSON,	REQ_URI )
VALUES ( #systemCd#, #level#, GETDATE(), #logJson#, #reqUri# )
